// Acc√®s localStorage s√©curis√© : en navigation priv√©e (Safari surtout), ou si le quota
// est plein, localStorage peut LEVER une exception et faire planter toute l'app (√©cran blanc).
// safeStorage encapsule chaque acc√®s dans un try/catch : en cas d'√©chec, on retombe sur un
// stockage m√©moire temporaire (perdu au refresh, mais l'app ne crashe jamais).
const _memStore = {};
const safeStorage = {
  getItem(key) {
    try { return window.localStorage.getItem(key); }
    catch { return key in _memStore ? _memStore[key] : null; }
  },
  setItem(key, value) {
    try { window.localStorage.setItem(key, value); }
    catch { _memStore[key] = String(value); }
  },
  removeItem(key) {
    try { window.localStorage.removeItem(key); }
    catch { delete _memStore[key]; }
  },
};

// ‚îÄ‚îÄ‚îÄ D√©tection PWA : sait-on d√©j√Ý install√© ? sur quel appareil ? ‚îÄ‚îÄ‚îÄ
// Sert √Ý afficher la bonne aide √Ý l'installation (bouton Android / instructions iOS).
function isStandalonePWA() {
  try {
    return window.matchMedia("(display-mode: standalone)").matches
      || window.navigator.standalone === true; // iOS
  } catch { return false; }
}
function isIOSDevice() {
  try {
    const ua = window.navigator.userAgent || "";
    return /iphone|ipad|ipod/i.test(ua)
      // iPad r√©cents se font passer pour Mac : on d√©tecte le tactile
      || (/macintosh/i.test(ua) && "ontouchend" in document);
  } catch { return false; }
}
// ‚îÄ‚îÄ‚îÄ D√©tection appli native (Capacitor/iOS) : conformit√© App Store 3.1.1 ‚îÄ‚îÄ‚îÄ
// Dans l'appli publi√©e sur l'App Store, on ne montre NI prix, NI abonnement,
// NI paiement (l'abonnement se g√®re sur le web). Le web reste inchang√© :
// window.Capacitor n'existe que dans l'appli native.
function isNativeApp() {
  try { return window.Capacitor?.isNativePlatform?.() === true; } catch { return false; }
}
const IS_NATIVE_APP = isNativeApp();

