  async function handleAddContact() {
    if (!contactForm.nom) return;
    try {
      await apiFetch("/contacts", {
        method: "POST",
        body: JSON.stringify({
          nom: contactForm.nom,
          email: contactForm.email || null,
          siret: contactForm.siret || null,
          adresse: contactForm.adresse || null,
        }),
      });
      setContactForm({ nom: "", email: "", siret: "", adresse: "" });
      setShowAddContact(false);
      await loadContacts();
    } catch (err) {
      setError(err.message);
    }
  }

  async function handleDeleteContact(id) {
    try {
      await apiFetch(`/contacts/${id}`, { method: "DELETE" });
      await loadContacts();
    } catch (err) {
      setError(err.message);
    }
  }

  useEffect(() => {
    // Contacts charg√©s aussi sur Factures, Devis et Frais : ils servent au
    // pr√©-remplissage des formulaires (la promesse de la page Contacts).
    if ((nav === "contacts" || nav === "factures" || nav === "devis" || nav === "frais") && token) loadContacts();
    // √âtat de l'encaissement en ligne : R√©glages + banni√®res Factures/Devis.
    if ((nav === "profil" || nav === "factures" || nav === "devis") && token) {
      apiFetch("/billing/connect/status").then(setConnectInfo).catch(() => {});
    }
  }, [nav, token]);

  // Retour du formulaire Stripe (?stripe_onboarding=retour|refresh) : relire
  // l'√©tat du dossier tout de suite (sinon la banni√®re reste p√©rim√©e) et
  // nettoyer l'URL. Le cas "refresh" (lien expir√©) retombe sur la banni√®re,
  // dont le bouton reg√©n√®re un lien frais.
  useEffect(() => {
    if (!token) return;
    if (!window.location.search.includes("stripe_onboarding")) return;
    apiFetch("/billing/connect/status").then(setConnectInfo).catch(() => {});
    try {
      const u = new URL(window.location.href);
      u.searchParams.delete("stripe_onboarding");
      window.history.replaceState({}, "", u.pathname + (u.search || "") + u.hash);
    } catch {}
  }, [token]);

  // ‚îÄ‚îÄ‚îÄ Pr√©-remplissage depuis les Contacts (factures ET devis) ‚îÄ‚îÄ‚îÄ
  // Tape un nom ‚Üí les contacts correspondants s'affichent en petites puces sous le
  // champ ; un clic remplit nom, email, adresse, SIRET (et passe en ¬´ professionnel ¬ª
  // si le contact a un SIRET). C'est la promesse affich√©e sur la page Contacts.
  function appliquerContact(c, form, setForm) {
    setForm({
      ...form,
      client_nom: c.nom,
      client_email: c.email || form.client_email,
      client_adresse: c.adresse || form.client_adresse,
      client_siret: c.siret || form.client_siret,
      client_type: c.siret ? "professionnel" : form.client_type,
    });
  }

  function renderSuggestionsContacts(form, setForm) {
    const saisie = (form.client_nom || "").trim().toLowerCase();
    if (!saisie) return null;
    const matches = contacts
      .filter(c => c.nom && c.nom.toLowerCase().includes(saisie) && c.nom.toLowerCase() !== saisie)
      .slice(0, 4);
    if (!matches.length) return null;
    return (
      <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 10, alignItems: "center" }}>
        <span style={{ fontSize: 11, color: "#8BA5C0" }}>Dans tes contacts :</span>
        {matches.map(c => (
          <button key={c.id} type="button" onClick={() => appliquerContact(c, form, setForm)}
            style={{ background: "#F0F7F4", border: "1px solid #CFE5DC", borderRadius: 999, padding: "4px 12px", fontSize: 12, color: "#0A2540", cursor: "pointer", fontFamily: "inherit" }}>
            {c.nom}
          </button>
        ))}
      </div>
    );
  }

