  async function apiFetch(path, options = {}) {
    // Timeout de s√©curit√© : si le backend ne r√©pond pas (ex : serveur qui se r√©veille
    // d'une mise en veille), on coupe au bout de 45s au lieu d'attendre ind√©finiment.
    // 45s laisse le temps √Ý Railway de se r√©veiller, sans bloquer l'utilisateur sans fin.
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), 45000);
    let res;
    try {
      res = await fetch(`${API_BASE}${path}`, {
        ...options,
        signal: ctrl.signal,
        headers: {
          ...(options.body && !(options.body instanceof FormData) ? { "Content-Type": "application/json" } : {}),
          ...(token ? authHeaders() : {}),
          ...options.headers,
        },
      });
    } catch (e) {
      clearTimeout(timer);
      if (e.name === "AbortError") throw new Error("Le serveur met du temps √Ý r√©pondre. V√©rifie ta connexion et r√©essaie.");
      throw new Error("Connexion impossible. V√©rifie ta connexion internet et r√©essaie.");
    }
    clearTimeout(timer);
    if (!res.ok) {
      const body = await res.json().catch(() => ({}));
      const isObj = body.detail && typeof body.detail === "object";
      // Quota gratuit atteint OU fonction premium ‚Üí on d√©clenche l'√©cran ¬´ passe en Premium ¬ª.
      if (isObj && (body.detail.code === "quota_gratuit_atteint" || body.detail.code === "premium_requis")) {
        setPremiumGate(body.detail);
        dernierMurPremium.current = body.detail.message || "";
      }
      const err = new Error(isObj ? (body.detail.message || "Erreur") : (body.detail || `Erreur (code ${res.status})`));
      if (isObj) err.detail = body.detail;
      err.status = res.status;
      throw err;
    }
    const data = await res.json();
    // Apr√®s une action qui consomme un quota, on rafra√Æchit le profil ‚Üí la jauge reste √Ý jour.
    if (["/assistant/chat", "/intermittent/aem/extract", "/income/extract", "/expenses/extract"].some(p => path.startsWith(p))) {
      apiFetch("/profile").then(setProfile).catch(() => {});
    }
    return data;
  }

  async function loadEverything() {
    setLoading(true);
    setError("");
    try {
      const p = await apiFetch("/profile");
      setProfile(p);
      // Code du jour de la secr√©taire vocale (abonn√©s) ‚Äî best effort, n'interrompt rien.
      apiFetch("/voice/code").then(setCodeVocal).catch(() => {});
      if (p.prenom != null) setProfilPrenom(p.prenom);
      if (p.nom != null) setProfilNom(p.nom);
      if (p.telephone != null) setProfilTelephone(p.telephone);
      if (p.entreprise != null) setProfilEntreprise(p.entreprise);
      if (p.depenses_mensuelles != null) setDepensesMensuelles(String(p.depenses_mensuelles));
      if (p.solde_bancaire != null) setPanique(prev => ({ ...prev, solde: String(p.solde_bancaire) }));
      if (p.email_verified != null) setEmailVerified(p.email_verified);
      if (p.siret != null) setProfilSiret(p.siret);
      if (p.adresse != null) setProfilAdresse(p.adresse);
      if (p.fiscal_settings) setVatNumber(p.fiscal_settings.vat_number || "");
      if (p.fiscal_settings) setFactureNumeroDepart(p.fiscal_settings.facture_numero_depart || "");
      if (p.reserve_securite != null) setObjectifSecurite(String(p.reserve_securite));
      if (p.tmi != null) setTmi(p.tmi);
      if (p.onboarding_complete) {
        const [est, inc, expSummary, proj, paie] = await Promise.all([apiFetch("/estimate"), apiFetch("/income"), apiFetch("/expenses/summary"), apiFetch("/projection").catch(() => null), apiFetch("/paie").catch(() => null)])
          .catch(e => { console.error("chargement des donn√©es:", e); throw new Error("Je n'arrive pas √Ý charger tes chiffres pour l'instant. V√©rifie ta connexion et recharge la page, je garde tout au chaud. üêæ"); });
        setEstimateData(est);
        setIncomeList(inc);
        setExpensesSummary(expSummary);
        setProjectionData(proj);
        setPaieData(paie);
        // √âtat de la connexion bancaire ‚Äî best effort, n'interrompt rien.
        loadBankStatus();
        // Ouvrir le walkthrough au premier acc√®s de CE compte uniquement.
        // `p.walkthrough_vu` vient du serveur : c'est lui qui survit √Ý une
        // r√©installation, contrairement au marqueur local.
        if (!walkthroughDejaVu(p.email, p.walkthrough_vu)) {
          setShowWalkthrough(true);
        }
      }
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  // Efface les donn√©es locales propres √Ý un compte (SIRET, adresse, objectifs...) pour √©viter
  // qu'elles ne "fuitent" d'un compte √Ý un autre sur le m√™me navigateur ‚Äî appel√©e √Ý CHAQUE
  // changement de session (connexion, inscription, d√©connexion), pas seulement √Ý la d√©connexion.
  function clearLocalAccountData() {
    ["profilPrenom", "profilNom", "profilTelephone", "profilEntreprise", "profilSiret", "profilAdresse",
     "objectifAnnuel", "objectifMensuel", "objectifSecurite", "depensesMensuelles", "tmi",
     "historiqueDeclarations", "actuHistorique", "landingStatut", "hector_walkthrough_done", "nav"].forEach(key => safeStorage.removeItem(key));
    setActuHistorique([]);
    setProfilPrenom("");
    setProfilNom("");
    setProfilTelephone("");
    setProfilEntreprise("");
    setProfilSiret("");
    setProfilAdresse("");
    setObjectifAnnuel("");
    setObjectifMensuel("");
    setObjectifSecurite("3000");
    setDepensesMensuelles("");
    setTmi("0");
    setHistoriqueDeclarations([]);
    setPanique(prev => ({ ...prev, solde: "" }));
    setSoldeSaveStatus("");
    soldeMounted.current = false;
    reserveMounted.current = false;
    tmiMounted.current = false;
  }

  // ¬´ Se connecter avec Apple ¬ª (iOS natif). M√™me fin de parcours que Google :
  // le backend renvoie { token } qu'on stocke comme jeton de session.
  async function handleAppleSignIn() {
    setError("");
    setLoading(true);
    try {
      const identifiants = await connexionApple();   // { identity_token, nonce } ‚Äî nonce BRUT
      if (!identifiants) return;                      // annul√© par la personne : silence
      const data = await apiFetch("/auth/apple", { method: "POST", body: JSON.stringify(identifiants) });
      clearLocalAccountData();
      safeStorage.setItem("token", data.token);
      setToken(data.token);
    } catch (err) {
      // Le backend renvoie parfois un mode d'emploi pr√™t √Ý afficher (compte Apple sans email).
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  function handleGoogleCredential(response) {
    setError("");
    setLoading(true);
    apiFetch("/auth/google", { method: "POST", body: JSON.stringify({ credential: response.credential, gclid: safeStorage.getItem("gclid") || null }) })
      .then(data => { clearLocalAccountData(); safeStorage.setItem("token", data.token); setToken(data.token); })
      .catch(err => setError(err.message))
      .finally(() => setLoading(false));
  }

  useEffect(() => { safeStorage.setItem("objectifAnnuel", objectifAnnuel); }, [objectifAnnuel]);
  useEffect(() => {
    if (!objectifAnnuelMounted.current) { objectifAnnuelMounted.current = true; return; }
    setObjectifAnnuelSaved(true);
    const t = setTimeout(() => setObjectifAnnuelSaved(false), 1200);
    return () => clearTimeout(t);
  }, [objectifAnnuel]);
  useEffect(() => { safeStorage.setItem("objectifMensuel", objectifMensuel); }, [objectifMensuel]);
  useEffect(() => {
    if (!objectifMounted.current) { objectifMounted.current = true; return; }
    setObjectifSaved(true);
    const t = setTimeout(() => setObjectifSaved(false), 1200);
    return () => clearTimeout(t);
  }, [objectifMensuel]);
  useEffect(() => { safeStorage.setItem("profilPrenom", profilPrenom); }, [profilPrenom]);
  useEffect(() => { safeStorage.setItem("profilNom", profilNom); }, [profilNom]);
  useEffect(() => { safeStorage.setItem("profilTelephone", profilTelephone); }, [profilTelephone]);
  useEffect(() => { safeStorage.setItem("profilEntreprise", profilEntreprise); }, [profilEntreprise]);
  useEffect(() => { safeStorage.setItem("profilSiret", profilSiret); }, [profilSiret]);
  useEffect(() => { safeStorage.setItem("profilAdresse", profilAdresse); }, [profilAdresse]);
  useEffect(() => { safeStorage.setItem("objectifSecurite", objectifSecurite); }, [objectifSecurite]);
  useEffect(() => { safeStorage.setItem("depensesMensuelles", depensesMensuelles); }, [depensesMensuelles]);
  useEffect(() => { safeStorage.setItem("autresRevenus", autresRevenus); }, [autresRevenus]);
  useEffect(() => { safeStorage.setItem("inclureAutresRevenus", String(inclureAutresRevenus)); }, [inclureAutresRevenus]);
  useEffect(() => { safeStorage.setItem("tmi", tmi); }, [tmi]);
  useEffect(() => { safeStorage.setItem("nav", nav); }, [nav]);

  // Message Totor si solde p√©rim√© (calcul interne, d√©clench√© une fois par session)
  useEffect(() => {
    if (nav !== "dashboard") return;
    const updatedAt = safeStorage.getItem("soldeUpdatedAt") || "";
    if (!updatedAt || panique.solde === "") return;
    const jours = Math.floor((Date.now() - new Date(updatedAt).getTime()) / (1000 * 60 * 60 * 24));
    if (jours >= 7 && !hectorMessagesSentRef.current.soldePerime) {
      hectorMessagesSentRef.current.soldePerime = true;
      addHectorMessage("√áa fait plus de 7 jours que je n'ai pas vu ton vrai solde. Mes calculs sont moins pr√©cis l√Ý. 10 secondes pour me mettre √Ý jour ?", "#FAC775");
    }
  }, [nav, panique.solde]);

  // Rafra√Æchit la projection tr√©sorerie d√®s que le solde est (re)sauvegard√© c√¥t√© serveur.
  useEffect(() => {
    if (soldeSaveStatus === "saved" && token) {
      apiFetch("/projection").then(setProjectionData).catch(() => {});
    }
  }, [soldeSaveStatus]); // eslint-disable-line react-hooks/exhaustive-deps

  // ‚îÄ‚îÄ‚îÄ STREAK : mise √Ý jour une fois par jour √Ý l'ouverture ‚îÄ‚îÄ‚îÄ
  useEffect(() => {
    if (!token) return;
    const today = new Date().toISOString().slice(0, 10);
    const lastDay = safeStorage.getItem("streakLastDay") || "";
    if (lastDay === today) return; // d√©j√Ý compt√© aujourd'hui
    const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0, 10);
    const current = parseInt(safeStorage.getItem("streakCount") || "0", 10);
    let newStreak;
    if (lastDay === yesterday) newStreak = current + 1; // continuit√©
    else if (lastDay === "") newStreak = 1; // premi√®re fois
    else newStreak = 1; // streak cass√©, on repart √Ý 1
    safeStorage.setItem("streakCount", String(newStreak));
    safeStorage.setItem("streakLastDay", today);
    // C√©l√©bration si on vient de franchir un palier
    const paliers = [7, 14, 30, 90, 180, 365];
    const palierMots = {
      7: "7 jours d'affil√©e üõèÔ∏è Totor dort maintenant paisiblement dans son panier. Tu prends soin de ta tranquillit√©.",
      14: "14 jours ensemble üå± Totor grandit gr√¢ce √Ý toi. Continue, vous formez une belle √©quipe.",
      30: "30 jours d'affil√©e üß∏ Totor a re√ßu un jouet ! Il est heureux de ce rituel avec toi.",
      90: "90 jours üè° Totor a maintenant une belle niche, confortable et s√ªre. Il se sent chez lui.",
      180: "180 jours ü¶¥ Totor est devenu adulte, serein et solide. Vous √™tes une vraie √©quipe.",
      365: "365 jours üëë Totor est le gardien l√©gendaire de ta tranquillit√©. Bravo pour cette ann√©e.",
    };
    if (paliers.includes(newStreak) && palierMots[newStreak]) {
      setTimeout(() => addHectorMessage(palierMots[newStreak], "#FAC775"), 1200);
    }
  }, [token]);

  const hectorMessagesSentRef = useRef({});

  useEffect(() => {
    if (token) loadEverything();
  }, [token]);

