  // R√©cup√®re l'√©tat de la connexion + le solde synchronis√©.
  async function loadBankStatus() {
    try {
      const data = await apiFetch("/bank/balance");
      setBankDispo(!!(data && data.disponible));
      setBankConnected(!!(data && data.connected));
      setBankBanqueNom((data && data.banque) || null);
      setBankIbanFin((data && data.iban_fin) || null);
      setBankExpiree(!!(data && data.expiree));
      if (data && data.solde != null) {
        setBankSolde(data.solde);
        // Le solde synchronis√© alimente le m√™me champ que la saisie manuelle.
        setPanique(prev => ({ ...prev, solde: String(data.solde) }));
        safeStorage.setItem("soldeUpdatedAt", new Date().toISOString());
      }
    } catch {
      // silencieux : pas de banque reli√©e ou backend pas encore pr√™t
    }
  }

  // D√©branche la banque (retour √Ý la saisie manuelle).
  async function handleBankDisconnect() {
    setBankLoading(true);
    try {
      await apiFetch("/bank/disconnect", { method: "POST" });
      setBankConnected(false);
      setBankSolde(null);
      addHectorMessage("Banque d√©branch√©e. Tu peux saisir ton solde √Ý la main quand tu veux.", "#5DCAA5");
    } catch (err) {
      addHectorMessage(err.message || "Impossible de d√©brancher pour le moment.", "#F0C36D");
    } finally {
      setBankLoading(false);
    }
  }

  // Traite le retour de la banque (/bank-callback?code=...) : √©change le code
  // contre une session Enable Banking et synchronise le solde.
  useEffect(() => {
    if (!bankCallbackCode) return;
    if (!token) return; // il faut √™tre authentifi√© pour enregistrer la connexion
    setBankSyncing(true);
    apiFetch("/bank/callback", {
      method: "POST",
      body: JSON.stringify({ code: bankCallbackCode }),
    })
      .then(data => {
        setBankConnected(true);
        setBankExpiree(false);
        if (data && data.solde != null) {
          setBankSolde(data.solde);
          setPanique(prev => ({ ...prev, solde: String(data.solde) }));
          safeStorage.setItem("soldeUpdatedAt", new Date().toISOString());
        }
        showToast("Banque connect√©e. Ton solde se met √Ý jour tout seul üêæ", "ti-building-bank");
        loadBankStatus();
      })
      .catch(err => {
        addHectorMessage(err.message || "La banque n'a pas confirm√© la connexion. R√©essaie.", "#F0C36D");
      })
      .finally(() => {
        // Nettoie l'URL (retire /bank-callback et les param√®tres) et revient √Ý l'app.
        window.history.replaceState({}, "", "/");
        setBankSyncing(false);
      });
  }, [bankCallbackCode, token]);

