    devis: ["Comment faire signer mon devis en ligne ?", "Comment faire un devis ?", "Comment transformer un devis en facture ?"],
    declaration: ["D'o√π vient le chiffre √Ý recopier ?", "Et si j'ai oubli√© un encaissement ?"],
