  // ‚îÄ‚îÄ Carnet de bord de Totor ("Ce que j'ai appris") ‚Äî visible par TOUS (gratuit inclus). ‚îÄ‚îÄ
  // Lit le fichier statique CARNET (√©dit√© √Ý la main). 3 cartes "en_cours" max, + encart
  // "Cette semaine, j'ai appris‚Ä¶" pour les "termine" dat√©s de moins de 7 jours.
  const renderCarnet = () => {
    const metier = profile?.statut === "intermittent" ? "intermittent" : "auto";
    const visible = (pub) => !pub || pub === "tous" || pub === metier;   // jamais le jargon de l'autre m√©tier
    const joursDepuis = (d) => Math.max(0, Math.floor((Date.now() - new Date(d + "T00:00:00").getTime()) / 86400000));
    const fmtJour = (d) => new Date(d + "T00:00:00").toLocaleDateString("fr-FR", { day: "numeric", month: "long" });
    const majTexte = (j) => (j <= 0 ? "aujourd'hui" : j === 1 ? "hier" : `il y a ${j} jours`);

    // Cartes en cours : on ne garde que les entr√©es visibles pour ce m√©tier, 3 cartes max.
    const cartes = (CARNET.enCours || [])
      .map(c => ({ ...c, entrees: (c.entrees || []).filter(e => visible(e.public)).sort((a, b) => b.date.localeCompare(a.date)) }))
      .filter(c => c.entrees.length)
      .sort((a, b) => b.entrees[0].date.localeCompare(a.entrees[0].date))
      .slice(0, 3);

    // Appris r√©cemment : visible pour ce m√©tier ET dat√© de moins de 7 jours.
    const appris = (CARNET.apprisRecemment || [])
      .filter(e => visible(e.public) && joursDepuis(e.date) <= 7)
      .sort((a, b) => b.date.localeCompare(a.date));

    return (
      <div style={{ maxWidth: 600, margin: "0 auto" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 18 }}>
          <div style={{ width: 48, height: 48, borderRadius: 14, background: "#0a1322", border: "1.5px solid rgba(55,138,221,0.4)", display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden", flexShrink: 0 }}>
            <NiveauImage src="/hector-tete.png" fallbackIcon="ti-notebook" fallbackColor="#378ADD" />
          </div>
          <div>
            <h1 style={{ fontSize: 20, fontWeight: 800, color: "white", margin: 0 }}>üê∂ Ce que j'ai appris</h1>
            <p style={{ fontSize: 13, color: "#8BA5C0", margin: "3px 0 0", lineHeight: 1.5 }}>Mes progr√®s r√©cents, pour mieux veiller sur toi. Je grandis un peu chaque semaine. üêæ</p>
          </div>
        </div>

        {cartes.length === 0 ? (
          <div style={{ ...S.card, textAlign: "center", color: "#8BA5C0", fontSize: 13, padding: "28px 20px" }}>
            üê∂ Je couve de nouvelles id√©es‚Ä¶ reviens bient√¥t voir ce que j'apprends pour toi.
          </div>
        ) : cartes.map((card, ci) => {
          const j = joursDepuis(card.entrees[0].date);
          return (
            <div key={ci} style={{ ...S.card, marginBottom: 14, borderLeft: `3px solid ${ACCENT}` }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}>
                <span style={{ width: 8, height: 8, borderRadius: "50%", background: "#5DCAA5", flexShrink: 0, boxShadow: "0 0 0 4px rgba(93,202,165,0.15)" }} />
                <span style={{ fontSize: 15, fontWeight: 700, color: "#E6EDF5" }}>{card.titre}</span>
                <span style={{ marginLeft: "auto", fontSize: 10, fontWeight: 700, color: "#5DCAA5", background: "rgba(93,202,165,0.12)", borderRadius: 6, padding: "2px 8px" }}>en cours</span>
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                {card.entrees.map((e, ei) => (
                  <div key={ei} style={{ display: "flex", gap: 10 }}>
                    <span style={{ width: 6, height: 6, borderRadius: "50%", background: ei === 0 ? ACCENT : "rgba(255,255,255,0.25)", flexShrink: 0, marginTop: 6 }} />
                    <div>
                      <div style={{ fontSize: 11, color: "#6B8299", marginBottom: 1 }}>{fmtJour(e.date)}</div>
                      <div style={{ fontSize: 13.5, color: "#C4D2E0", lineHeight: 1.5 }}>{e.texte}</div>
                    </div>
                  </div>
                ))}
              </div>
              <div style={{ fontSize: 11.5, color: "#6B8299", marginTop: 12, borderTop: "1px solid rgba(255,255,255,0.06)", paddingTop: 10 }}>
                üìÖ Derni√®re mise √Ý jour : {majTexte(j)}
              </div>
            </div>
          );
        })}

        {appris.length > 0 && (
          <div style={{ background: "rgba(93,202,165,0.08)", border: "1px solid rgba(93,202,165,0.25)", borderRadius: 12, padding: "16px 18px", marginTop: 6 }}>
            <div style={{ fontSize: 14, fontWeight: 700, color: "#5DCAA5", marginBottom: 10 }}>üê∂ Cette semaine, j'ai appris‚Ä¶</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {appris.map((e, i) => (
                <div key={i} style={{ display: "flex", gap: 8, fontSize: 13.5, color: "#C4D2E0", lineHeight: 1.45 }}>
                  <span style={{ color: "#5DCAA5", flexShrink: 0 }}>‚úì</span>
                  <span>{e.texte}</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  };

  // Jauge de quota ‚Äî c√¥t√© GRATUIT uniquement. Lit profile.quotas[type] = { used, limit }.
  // Masqu√©e si abonn√© (pas de limite) OU si la limite est neutralis√©e (> 100, ex. 9999).
  // Formule positive (ce qu'il reste) + phrase-promesse r√©currente. Couleurs de marque.
  const renderQuotaJauge = (type, nomSingulier) => {
    if (profile?.is_premium) return null;
    const q = profile?.quotas?.[type];
    if (!q || typeof q.limit !== "number" || q.limit > 100) return null;
    const used = Math.max(0, Math.min(q.used, q.limit));
    const reste = Math.max(0, q.limit - used);
    return (
      <div style={{ background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.08)", borderRadius: 12, padding: "12px 14px", marginBottom: 14 }}>
        <div style={{ display: "flex", gap: 4 }}>
          {Array.from({ length: q.limit }).map((_, i) => (
            <div key={i} style={{ flex: 1, height: 6, borderRadius: 3, background: i < used ? ACCENT : "rgba(255,255,255,0.12)" }} />
          ))}
        </div>
        <div style={{ fontSize: 12.5, color: "#E6EDF5", fontWeight: 600, marginTop: 8 }}>
          {reste > 0
            ? `üê∂ Offre gratuite : il te reste ${reste} ${nomSingulier}${reste > 1 ? "s" : ""} ce mois-ci`
            : `üê∂ Tu as fait le plein de ${nomSingulier}s ce mois-ci üëè`}
        </div>
        {/* Appli native : pas d'incitation √Ý l'abonnement (App Store 3.1.1). */}
        {!IS_NATIVE_APP && <div style={{ fontSize: 11.5, color: "#8BA5C0", marginTop: 3 }}>
          üê∂ Je pourrais m'en occuper autant de fois que tu veux :{" "}
          <button type="button" onClick={() => (profile?.statut === "intermittent" ? setInterNav("abonnement") : setNav("abonnement"))}
            style={{ background: "none", border: "none", color: "#5DCAA5", fontWeight: 700, fontSize: 11.5, cursor: "pointer", fontFamily: "inherit", padding: 0, textDecoration: "underline" }}>
            voir l'offre illimit√©e ‚Üí
          </button>
        </div>}
      </div>
    );
  };

  const [exportingData, setExportingData] = useState(false);
  const [showDeleteAccount, setShowDeleteAccount] = useState(false);
  const [deleteConfirmText, setDeleteConfirmText] = useState("");
  const [deletingAccount, setDeletingAccount] = useState(false);

  const [pwdCurrent, setPwdCurrent] = useState("");
  const [pwdNew, setPwdNew] = useState("");
  const [pwdConfirm, setPwdConfirm] = useState("");
  const [pwdSaving, setPwdSaving] = useState(false);
  const [pwdMsg, setPwdMsg] = useState("");
  const [pwdErr, setPwdErr] = useState("");

  async function handleChangePassword() {
    setPwdErr(""); setPwdMsg("");
    if (pwdNew.length < 8) { setPwdErr("Le nouveau mot de passe doit contenir au moins 8 caract√®res."); return; }
    if (pwdNew !== pwdConfirm) { setPwdErr("La confirmation ne correspond pas."); return; }
    setPwdSaving(true);
    try {
      await apiFetch("/auth/change-password", {
        method: "POST",
        body: JSON.stringify({ current_password: pwdCurrent, new_password: pwdNew }),
      });
      setPwdMsg("‚úì Mot de passe chang√©.");
      setPwdCurrent(""); setPwdNew(""); setPwdConfirm("");
    } catch (err) {
      setPwdErr(err.message || "Impossible de changer le mot de passe.");
    } finally {
      setPwdSaving(false);
    }
  }

  // ‚îÄ‚îÄ‚îÄ ¬´ Ton avis compte ¬ª : d√©p√¥t d'avis avec consentement de publication explicite. ‚îÄ‚îÄ‚îÄ
  // Part par email √Ý l'√©quipe (aucun stockage) ; seuls les avis consentis pourront √™tre
  // publi√©s sur le site, avec pr√©nom + m√©tier. Le circuit l√©gal des VRAIS t√©moignages.
  async function envoyerAvis() {
    if (avisSaving) return;
    setAvisErr("");
    setAvisSaving(true);
    try {
      await apiFetch("/avis", {
        method: "POST",
        body: JSON.stringify({
          message: avisTexte,
          prenom: profilPrenom || null,
          metier: profile?.statut === "intermittent" ? "intermittent du spectacle" : "auto-entrepreneur",
          consentement_publication: avisConsent,
        }),
      });
      setAvisEnvoye(true);
      setAvisTexte("");
    } catch (err) {
      setAvisErr(err.message || "L'envoi a √©chou√©. R√©essaie dans un moment.");
    } finally {
      setAvisSaving(false);
    }
  }

