  function ouvrirAllocEdit(alloc) {
    // Pr√©-remplit avec les valeurs d√©j√Ý saisies, si elles existent.
    setAllocAnnexe(alloc?.annexe || "annexe10");
    setAllocSR(alloc?.salaire_reference != null ? String(alloc.salaire_reference) : "");
    setAllocNHT(alloc?.heures_reference != null ? String(alloc.heures_reference) : "");
    setAllocEdit(true);
  }

  async function handleSaveAllocation() {
    const sr = parseFloat(String(allocSR).replace(",", "."));
    const nht = parseFloat(String(allocNHT).replace(",", "."));
    if (isNaN(sr) || isNaN(nht) || sr < 0 || nht < 0) {
      setError("Renseigne un salaire de r√©f√©rence et un nombre d'heures valides.");
      return;
    }
    setAllocSaving(true);
    try {
      await apiFetch("/intermittent/allocation", {
        method: "POST",
        body: JSON.stringify({ annexe: allocAnnexe, salaire_reference: sr, heures_reference: nht }),
      });
      setAllocEdit(false);
      await loadIntermittentCockpit();
    } catch (err) {
      setError(err.message);
    } finally {
      setAllocSaving(false);
    }
  }

  // ‚îÄ‚îÄ‚îÄ Import attestation ARE : Totor LIT (date anniversaire + montant journalier),
  // il ne calcule rien. On affiche ce que France Travail a d√©j√Ý d√©cid√©. ‚îÄ‚îÄ‚îÄ
  // Backend en place : POST /intermittent/are/extract (multipart "file") renvoie
  // { date_anniversaire, montant_journalier, filename }.
  async function handleImportARE(file) {
    setAreUploading(true);
    setAreError("");
    setAreExtrait(null);
    try {
      const form = new FormData();
      form.append("file", file);
      const data = await apiFetch("/intermittent/are/extract", { method: "POST", body: form });
      // Lecture vide (ni date, ni montant) : message honn√™te plut√¥t qu'un formulaire vide muet.
      if (!data.date_anniversaire && data.montant_journalier == null) {
        setAreError("Je n'ai trouv√© ni ta date anniversaire ni ton allocation sur ce document. V√©rifie que c'est bien la notification de droits de France Travail (le courrier ¬´ d√©cision ¬ª), et que la photo est nette. Tu peux aussi saisir les valeurs √Ý la main.");
        return;
      }
      // Pr√©-remplit l'√©cran de v√©rification avec ce que Totor a lu (tout reste √©ditable).
      setAreExtrait({
        date_anniversaire: data.date_anniversaire || "",
        montant_journalier: data.montant_journalier != null ? String(data.montant_journalier) : "",
        filename: data.filename || file.name,
      });
    } catch (err) {
      setAreError(err.message || "Lecture impossible. R√©essaie avec un document plus net.");
    } finally {
      setAreUploading(false);
    }
  }

  // ‚îÄ‚îÄ‚îÄ Confirme l'ARE lue : enregistre la date anniversaire (+ le montant journalier,
  // affich√© tel quel, jamais recalcul√©). ‚îÄ‚îÄ‚îÄ
  async function handleConfirmARE() {
    if (!areExtrait || !areExtrait.date_anniversaire) {
      setAreError("V√©rifie la date anniversaire avant d'enregistrer.");
      return;
    }
    setAreSaving(true);
    setAreError("");
    try {
      const mj = areExtrait.montant_journalier !== "" ? parseFloat(areExtrait.montant_journalier) : null;
      // BACKEND √Ä FAIRE ‚Äî accepter un champ optionnel "montant_journalier" sur cet endpoint
      // (ou un endpoint d√©di√©) pour stocker le montant lu et le ressortir dans le cockpit.
      await apiFetch("/profile/date-anniversaire", {
        method: "POST",
        body: JSON.stringify({
          date_anniversaire: areExtrait.date_anniversaire || null,
          montant_journalier: mj != null && !isNaN(mj) ? mj : null,
        }),
      });
      setAreExtrait(null);
      await loadIntermittentCockpit();
    } catch (err) {
      setAreError(err.message);
    } finally {
      setAreSaving(false);
    }
  }

