  // Rendu du bloc de totaux (HT / TVA ou mention 293 B / TTC). Le calcul vient de
  // computeInvoiceTotals (jumeau backend) ‚Äî pas de logique TVA dupliqu√©e ici.
  // montantHt = total HT ; `flex` = variante de style des vues d√©tail.
  // Switch ¬´ Particulier / Professionnel ¬ª + champs SIRET/TVA client (pro uniquement).
  // `patch` fusionne un objet partiel dans le form (facture ou devis).
  function renderClientType(form, patch) {
    const pro = form.client_type === "professionnel";
    return (
      <>
        <div style={{ display: "flex", gap: 8, marginBottom: 10 }}>
          {[{ v: "particulier", label: "Particulier" }, { v: "professionnel", label: "Professionnel" }].map(opt => {
            const actif = form.client_type === opt.v;
            return (
              <button key={opt.v} type="button" onClick={() => patch({ client_type: opt.v })}
                style={{
                  flex: 1, background: actif ? "#5DCAA5" : "white", color: actif ? "#04342C" : INK,
                  border: `1.5px solid ${actif ? "#5DCAA5" : "#E2E9F0"}`, borderRadius: 8, padding: "9px 10px",
                  fontSize: 12.5, fontWeight: 600, cursor: "pointer", fontFamily: "inherit",
                }}>{opt.label}</button>
            );
          })}
        </div>
        {pro && (
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 10 }}>
            <input style={S.input} placeholder="SIRET client (optionnel)" value={form.client_siret}
              onChange={e => patch({ client_siret: e.target.value })} />
            <input style={S.input} placeholder={form.client_localisation === "ue" ? "N¬∞ TVA client (obligatoire)" : "N¬∞ TVA client (optionnel)"} value={form.client_tva}
              onChange={e => patch({ client_tva: e.target.value })} />
          </div>
        )}
        {/* Localisation du client PRO : uniquement pour un √©metteur assujetti √Ý la TVA.
            D√©cide, document par document, la TVA 0 % + mention art. 259-1 (¬± Autoliquidation).
            Sources v√©rifi√©es 08/07/2026 ‚Äî voir legalMentions.js (jumeau backend). */}
        {pro && profile?.fiscal_settings?.vat_mode === "assujetti" && (
          <div style={{ marginBottom: 10 }}>
            <div style={{ fontSize: 11, color: "#8BA5C0", marginBottom: 6 }}>Localisation du client</div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              {[
                { v: "france", label: "France" },
                { v: "ue", label: "UE (hors France)" },
                { v: "hors_ue", label: "Hors UE" },
              ].map(opt => {
                const actif = (form.client_localisation || "france") === opt.v;
                return (
                  <button key={opt.v} type="button" onClick={() => patch({ client_localisation: opt.v })}
                    style={{
                      flex: "1 1 auto", background: actif ? "#5DCAA5" : "white", color: actif ? "#04342C" : INK,
                      border: `1.5px solid ${actif ? "#5DCAA5" : "#E2E9F0"}`, borderRadius: 8, padding: "9px 10px",
                      fontSize: 12.5, fontWeight: 600, cursor: "pointer", fontFamily: "inherit",
                    }}>{opt.label}</button>
                );
              })}
            </div>
            {form.client_localisation === "ue" && (
              <div style={{ fontSize: 11, color: "#854F0B", background: "rgba(250,199,117,0.15)", border: "1px solid rgba(250,199,117,0.4)", borderRadius: 8, padding: "8px 10px", marginTop: 8, lineHeight: 1.5 }}>
                TVA √Ý 0 % en autoliquidation : le n¬∞ de TVA de ton client est obligatoire sur la facture.
                Pense aussi √Ý ta D√©claration europ√©enne de services (DES) sur douane.gouv.fr pour ce mois.
              </div>
            )}
            {form.client_localisation === "hors_ue" && (
              <div style={{ fontSize: 11, color: "#8BA5C0", marginTop: 8, lineHeight: 1.5 }}>
                TVA √Ý 0 % : la facture portera la mention ¬´ TVA non applicable, art. 259-1 du CGI ¬ª.
              </div>
            )}
          </div>
        )}
      </>
    );
  }

  // fiscalSnap : r√©gime FIG√â d'une facture/devis existant (snapshot). Si absent (formulaire
  // de cr√©ation), on prend le r√©glage courant (la pi√®ce n'est pas encore √©mise).
  // localisation : "ue" | "hors_ue" choisi dans le FORMULAIRE (client pro √Ý l'√©tranger) ‚Äî
  // reproduit exactement ce que le backend figera, pour un aper√ßu fid√®le.
  function renderTotaux(montantHt, flex = false, fiscalSnap = null, localisation = null) {
    let fiscal = fiscalSnap || profile?.fiscal_settings;
    if (!fiscalSnap && fiscal?.vat_mode === "assujetti" && (localisation === "ue" || localisation === "hors_ue")) {
      fiscal = { ...fiscal, vat_mode: localisation === "ue" ? "assujetti_ue" : "assujetti_export" };
    }
    const t = computeInvoiceTotals(montantHt, fiscal);
    const base = flex ? { display: "flex", justifyContent: "space-between" } : { ...S.netRow };
    const htStyle = flex ? { ...base, fontSize: 13, fontWeight: 600 } : { ...base, fontWeight: 600 };
    const ttcStyle = flex
      ? { ...base, fontSize: 14, fontWeight: 700, borderTop: "1px solid #DDE5EE", paddingTop: 8, marginTop: 8 }
      : { ...base, fontWeight: 600, borderTop: "1px solid #DDE5EE", paddingTop: 8, marginTop: 4 };
    const midStyle = {
      ...base, fontSize: 11, marginTop: flex ? 4 : 0,
      color: t.mode === "assujetti" ? "#0A2540" : (flex ? "#6B7A8D" : "#8BA5C0"),
    };
    return (
      <>
        <div style={htStyle}><span>Total HT</span><span>{formatEUR(t.ht)}</span></div>
        {t.mode === "assujetti"
          ? <div style={midStyle}><span>TVA ({formatVatRate(t.rate)} %)</span><span>{formatEUR(t.tva)}</span></div>
          : <div style={midStyle}><span style={{ maxWidth: "78%" }}>{t.mention}</span><span>0,00 ‚Ç¨</span></div>}
        <div style={ttcStyle}><span>Total TTC</span><span>{formatEUR(t.ttc)}</span></div>
      </>
    );
  }

