          {/* L'√©cran Veille (vitrine plein √©cran occasionnelle) + murmure (gratuits) */}
          {interNav !== "abonnement" && ecranVeilleModal}
          {interNav === "cockpit" && renderMurmureVeille(() => setInterNav("abonnement"))}

          {/* ‚îÄ‚îÄ‚îÄ V√©rification d'email : masqu√©e sur la vitrine de vente ‚îÄ‚îÄ‚îÄ */}
