                const fmtDate = (iso) => { try { const d = new Date(iso); const M = ["jan","f√©v","mar","avr","mai","juin","juil","ao√ªt","sep","oct","nov","d√©c"]; return `${d.getDate()} ${M[d.getMonth()]} ${d.getFullYear()}`; } catch { return iso; } };

                // ‚îÄ‚îÄ 1) VICTOIRE (apr√®s le dernier scan valid√© du batch) ‚îÄ‚îÄ
