                        <button onClick={() => setNav("achat")} style={{ background: "none", border: "none", color: "#8BA5C0", fontSize: 12, cursor: "pointer", fontFamily: "inherit", padding: "8px 6px", textAlign: "left", minHeight: 44, display: "inline-flex", alignItems: "center" }}>üõí Simuler un achat ‚Üí</button>
