                      <button onClick={() => { setAiInput("Ma tr√©sorerie est dans le rouge. Qu'est-ce que je peux faire concr√®tement ?"); setNav("assistant"); }}
                        style={{ background: "none", border: "none", color: "#F09595", fontSize: 12, cursor: "pointer", fontFamily: "inherit", padding: "8px 6px", textAlign: "left", minHeight: 44, display: "inline-flex", alignItems: "center" }}>En parler √Ý Totor ‚Üí</button>
